const input = $input.first().json;

// FIX: Get data from body (webhook wraps POST data in body)
const body = input.body || input;
const msg = body.user_message || body.message || '';
const lang = body.language || (/[\u0600-\u06FF]/.test(msg) ? 'ar' : 'en');
const sessionId = body.session_id || 'session_' + Date.now();
const channel = body.channel || 'chat';

// Intent detection
let agent = 'support';
let intent = 'GENERAL';
let matched = [];

// Arabic keywords
if (msg.includes('سعر') || msg.includes('بكام') || msg.includes('كام')) {
  agent = 'sales'; intent = 'SALES_PRICE'; matched.push('price_ar');
}
else if (msg.includes('مشكلة') || msg.includes('شكوى')) {
  agent = 'complaint'; intent = 'COMPLAINT'; matched.push('complaint_ar');
}
else if (msg.includes('ضمان')) {
  agent = 'warranty'; intent = 'WARRANTY'; matched.push('warranty_ar');
}
else if (msg.includes('توصيل') || msg.includes('شحن')) {
  agent = 'support'; intent = 'DELIVERY'; matched.push('delivery_ar');
}
else if (msg.includes('مرتبة') || msg.includes('اشتري')) {
  agent = 'sales'; intent = 'SALES'; matched.push('sales_ar');
}
// English keywords
else if (msg.toLowerCase().includes('price') || msg.toLowerCase().includes('cost') || msg.toLowerCase().includes('how much')) {
  agent = 'sales'; intent = 'SALES_PRICE'; matched.push('price_en');
}
else if (msg.toLowerCase().includes('problem') || msg.toLowerCase().includes('complaint') || msg.toLowerCase().includes('issue')) {
  agent = 'complaint'; intent = 'COMPLAINT'; matched.push('complaint_en');
}
else if (msg.toLowerCase().includes('warranty') || msg.toLowerCase().includes('guarantee')) {
  agent = 'warranty'; intent = 'WARRANTY'; matched.push('warranty_en');
}
else if (msg.toLowerCase().includes('delivery') || msg.toLowerCase().includes('shipping')) {
  agent = 'support'; intent = 'DELIVERY'; matched.push('delivery_en');
}
else if (msg.toLowerCase().includes('mattress') || msg.toLowerCase().includes('buy')) {
  agent = 'sales'; intent = 'SALES'; matched.push('sales_en');
}

// Generate response
const responses = {
  sales: {
    SALES_PRICE: { ar: 'تمام! أسعار المراتب عندنا بتبدأ من 12,500 جنيه. عايز تعرف تفاصيل أكتر؟', en: 'Great! Our mattress prices start from 12,500 EGP. Would you like more details?' },
    SALES: { ar: 'أهلاً! أنا هنا أساعدك تختار المرتبة المناسبة ليك.', en: 'Hello! I am here to help you choose the right mattress.' }
  },
  complaint: {
    COMPLAINT: { ar: 'معلش جداً على اللي حصل. فاهم زعلك تماماً. ممكن تقولي إيه اللي حصل بالظبط؟', en: 'I am truly sorry about what happened. Can you tell me what exactly occurred?' }
  },
  warranty: {
    WARRANTY: { ar: 'ضمان يانسن 10 سنين وبيغطي عيوب الصناعة. محتاج مساعدة في الضمان؟', en: 'Janssen warranty is 10 years covering manufacturing defects. Need help?' }
  },
  support: {
    DELIVERY: { ar: 'التوصيل للقاهرة والجيزة خلال 2-3 أيام عمل. باقي المحافظات 5-7 أيام.', en: 'Delivery to Cairo/Giza is 2-3 business days. Other areas 5-7 days.' },
    GENERAL: { ar: 'أهلاً! أنا هنا أساعدك. اتفضل اسألني!', en: 'Hello! I am here to help. Please ask me anything!' }
  }
};

const text = responses[agent]?.[intent]?.[lang] || responses.support.GENERAL[lang];

return {
  json: {
    response_type: 'text',
    content: { text: text },
    next_action: 'await_response',
    agent_used: agent,
    intent: intent,
    confidence_score: matched.length > 0 ? 0.85 : 0.5,
    session_id: sessionId,
    matched_keywords: matched,
    language: lang
  }
};
